        // 函数 - 加载世界书
        async function loadWorldBooks() {
          loading.style.display = 'block';
          worldBookSelect.innerHTML = '<option value="">-- 加载中 --</option>'; // 显示加载状态
          try {
            // 在调用前再次检查函数是否存在，增加健壮性
            if (typeof getLorebooks !== 'function') {
              console.error('getLorebooks function is not defined when trying to load world books.');
              alert('加载世界书失败：所需函数丢失。');
              loading.textContent = '加载世界书失败，函数丢失。';
              loading.style.color = 'var(--danger-color)';
              return; // 提前退出
            }

            allWorldBooks = await getLorebooks(); // 存储所有世界书到变量
            displayWorldBooks(); // 调用新的显示函数

            // 注意：选中逻辑移到 displayWorldBooks 函数中处理
            if (currentWorldBook && !allWorldBooks.includes(currentWorldBook)) {
              // 如果之前选中的书已不存在 (可能被删除了)
              currentWorldBook = '';
              saveSelectedWorldBookToChatVars(); // 更新聊天变量
              entryList.innerHTML = '';
              noEntriesMessage.style.display = 'block';
            } else if (currentWorldBook) {
              worldBookSelect.value = currentWorldBook;
              // 并加载其条目
              await loadEntries(currentWorldBook);
            } else {
              // 如果没有选中过，确保条目列表是空的
              currentWorldBook = '';
              entryList.innerHTML = '';
              noEntriesMessage.style.display = 'block';
            }
          } catch (error) {
            console.error('加载世界书失败', error);
            alert('加载世界书失败: ' + error.message);
          } finally {
            loading.style.display = 'none';
          }
        }

        // 新增：函数 - 根据搜索词显示世界书列表
        function displayWorldBooks(searchTerm = '') {
          const lowerSearchTerm = searchTerm.toLowerCase();

          // 过滤世界书
          const filteredBooks = allWorldBooks.filter(book => book.toLowerCase().includes(lowerSearchTerm));

          // 清空现有选项
          worldBookSelect.innerHTML = '';

          // 添加默认选项
          const emptyOption = document.createElement('option');
          emptyOption.value = '';
          emptyOption.textContent =
            filteredBooks.length === 0 && searchTerm ? '-- 无匹配世界书 --' : '-- 请选择世界书 --';
          worldBookSelect.appendChild(emptyOption);

          // 添加过滤后的选项
          filteredBooks.forEach(book => {
            const option = document.createElement('option');
            option.value = book;
            option.textContent = book;
            worldBookSelect.appendChild(option);
          });

          // 检查当前选中的世界书是否仍在过滤结果中
          if (currentWorldBook && filteredBooks.includes(currentWorldBook)) {
            worldBookSelect.value = currentWorldBook; // 保持选中
          } else if (currentWorldBook && !filteredBooks.includes(currentWorldBook)) {
            // 如果当前选中的不在过滤结果中，取消选中状态，但不清除条目列表
            // 用户需要手动选择一个新的或清除搜索
            worldBookSelect.value = '';
          } else {
            // 如果本来就没选中，保持空值
            worldBookSelect.value = '';
          }
        }

        // 函数 - 加载条目
        async function loadEntries(worldBook) {
          loading.style.display = 'block';
          entryList.innerHTML = '';

          try {
            entries = await getLorebookEntries(worldBook);
            if (entries.length === 0) {
              noEntriesMessage.style.display = 'block';
            } else {
              noEntriesMessage.style.display = 'none';
              filterAndDisplayEntries();
            }
          } catch (error) {
            console.error('加载条目失败', error);
            alert('加载条目失败: ' + error.message);
            noEntriesMessage.style.display = 'block';
          } finally {
            loading.style.display = 'none';
          }
        }

        // 函数 - 筛选和显示条目
        function filterAndDisplayEntries() {
          const searchTerm = searchInput.value.toLowerCase();

          filteredEntries = entries.filter(entry => {
            // 应用过滤器
            if (currentFilter === 'enabled' && !entry.enabled) return false;
            if (currentFilter === 'disabled' && entry.enabled) return false;
            if (currentFilter === 'constant' && entry.type !== 'constant') return false;
            if (currentFilter === 'selective' && entry.type !== 'selective') return false;
            if (currentFilter === 'vectorized' && entry.type !== 'vectorized') return false;

            // 新增：应用位置过滤器
            if (currentFilter === 'pos_before_char' && entry.position !== 'before_character_definition') return false;
            if (currentFilter === 'pos_after_char' && entry.position !== 'after_character_definition') return false;
            if (currentFilter === 'pos_before_ex' && entry.position !== 'before_example_messages') return false;
            if (currentFilter === 'pos_after_ex' && entry.position !== 'after_example_messages') return false;
            if (currentFilter === 'pos_before_an' && entry.position !== 'before_author_note') return false;
            if (currentFilter === 'pos_after_an' && entry.position !== 'after_author_note') return false;
            if (currentFilter === 'pos_depth_sys' && entry.position !== 'at_depth_as_system') return false;
            if (currentFilter === 'pos_depth_asst' && entry.position !== 'at_depth_as_assistant') return false;
            if (currentFilter === 'pos_depth_user' && entry.position !== 'at_depth_as_user') return false;

            // 新增：应用深度筛选 (仅当@D过滤器激活时)
            if (currentFilter.startsWith('pos_depth_') && depthFilterInput.value !== '') {
              const filterDepth = parseInt(depthFilterInput.value);
              if (isNaN(filterDepth) || entry.depth !== filterDepth) {
                return false;
              }
            }

            // 应用搜索
            if (searchTerm) {
              return (
                entry.comment.toLowerCase().includes(searchTerm) ||
                entry.content.toLowerCase().includes(searchTerm) ||
                entry.keys.some(k => k.toLowerCase().includes(searchTerm))
              );
            }

            return true;
          });

          // 在显示前进行排序
          const sortedEntries = sortEntries(filteredEntries, currentSortMode);

          displayEntries(sortedEntries); // 使用排序后的条目进行显示
        }

        /**
         * 创建单个条目元素的公共函数
         * @param {Object} entry 条目数据
         * @param {boolean} isPreview 是否为预览模式 (添加复选框)
         * @param {number} [index] 条目在数组中的索引 (预览模式下需要)
         * @returns {HTMLElement} 创建的条目DOM元素
         */
        function createEntryElement(entry, isPreview = false, index = -1) {
          const entryItem = document.createElement('div');
          entryItem.className = 'entry-item';

          // 如果是预览模式，添加复选框
          if (isPreview && index !== -1) {
            const checkbox = document.createElement('input');
            checkbox.type = 'checkbox';
            checkbox.className = 'import-entry-checkbox';
            checkbox.dataset.index = index;
            checkbox.checked = selectedImportIndices.has(index); // 根据集合设置初始状态
            checkbox.addEventListener('change', function () {
              const entryIndex = parseInt(checkbox.dataset.index);
              if (checkbox.checked) {
                selectedImportIndices.add(entryIndex);
              } else {
                selectedImportIndices.delete(entryIndex);
              }
              updateImportSelectionCounter();
              // 更新全选框状态
              selectAllImportCheckboxFromPreview.checked = selectedImportIndices.size === entriesToImport.length;
            });
            entryItem.appendChild(checkbox);
          }

          // 根据条目类型设置不同的边框颜色
          if (entry.type === 'constant') {
            entryItem.style.borderLeftColor = '#3a7bd5'; // 使用主色调变量
          } else if (entry.type === 'selective') {
            entryItem.style.borderLeftColor = '#4caf50'; // 使用成功色变量
          } else if (entry.type === 'vectorized') {
            entryItem.style.borderLeftColor = '#9c27b0'; // 使用一个更明显的紫色
          }

          // 如果条目被禁用，显示灰色
          if (!entry.enabled) {
            entryItem.style.opacity = '0.7';
          }

          const header = document.createElement('div');
          header.className = 'entry-header';

          const title = document.createElement('div');
          title.className = 'entry-title';
          title.textContent = entry.comment || '无标题';

          const statusBadge = document.createElement('span');
          statusBadge.textContent = entry.enabled ? '已启用' : '已禁用';
          statusBadge.style.backgroundColor = entry.enabled ? 'var(--success-color)' : 'var(--danger-color)';
          statusBadge.style.color = 'white';
          statusBadge.style.padding = '0.2rem 0.5rem';
          statusBadge.style.borderRadius = '4px';
          statusBadge.style.fontSize = '0.75rem';

          header.appendChild(title);
          header.appendChild(statusBadge);
          entryItem.appendChild(header);

          const meta = document.createElement('div');
          meta.className = 'entry-meta';

          // 显示UID
          const uidSpan = document.createElement('span');
          uidSpan.textContent = 'UID: ' + entry.uid;
          meta.appendChild(uidSpan);

          // 显示类型
          const typeSpan = document.createElement('span');
          const typeNames = {
            constant: '常量（蓝灯）',
            selective: '选择性（绿灯）',
            vectorized: '向量化（紫灯）',
          };
          typeSpan.textContent = '类型: ' + (typeNames[entry.type] || entry.type);
          meta.appendChild(typeSpan);

          // 显示位置
          const positionSpan = document.createElement('span');
          const positionNames = {
            before_character_definition: '角色定义之前',
            after_character_definition: '角色定义之后',
            before_example_messages: '示例消息之前',
            after_example_messages: '示例消息之后',
            before_author_note: '作者注释之前',
            after_author_note: '作者注释之后',
            at_depth_as_system: '@D⚙',
            at_depth_as_assistant: '@D👤',
            at_depth_as_user: '@D🤖',
          };
          positionSpan.textContent = '位置: ' + (positionNames[entry.position] || entry.position);
          if (entry.position.startsWith('at_depth_as_') && entry.depth !== null) {
            positionSpan.textContent += ` (深度: ${entry.depth})`;
          }
          meta.appendChild(positionSpan);

          // 显示顺序
          const orderSpan = document.createElement('span');
          orderSpan.textContent = '顺序: ' + entry.order;
          meta.appendChild(orderSpan);

          // 显示概率
          const probabilitySpan = document.createElement('span');
          probabilitySpan.textContent = '概率: ' + entry.probability + '%';
          meta.appendChild(probabilitySpan);

          entryItem.appendChild(meta);

          // 显示关键词标签
          if (entry.keys && entry.keys.length > 0) {
            const tagList = document.createElement('div');
            tagList.className = 'tag-list';

            const logicNames = {
              and_any: '任意一个关键词（OR）',
              and_all: '所有关键词（AND）',
              not_all: '排除所有关键词',
              not_any: '排除任意关键词',
            };

            const logicTag = document.createElement('div');
            logicTag.className = 'tag';
            logicTag.style.backgroundColor = '#e1d5e7'; // 浅紫色背景
            logicTag.style.color = '#000';
            logicTag.textContent = logicNames[entry.logic] || entry.logic;
            tagList.appendChild(logicTag);

            entry.keys.forEach(keyword => {
              if (keyword) {
