        }

        // 函数 - 更新已选择计数
        function updateSelectedCounter() {
          selectedCounter.textContent = `已选择: ${selectedEntries.size} 项`;
        }

        // 函数 - 应用批量属性修改
        async function applyBatchPropertyChange(property, value) {
          if (selectedEntries.size === 0) {
            alert('请先选择要修改的条目');
            return;
          }

          batchLoading.style.display = 'block';

          try {
            const updatedEntries = [];

            // 为每个选中的条目创建更新对象
            for (const uid of selectedEntries) {
              updatedEntries.push({
                uid: uid,
                [property]: value,
              });
            }

            // 更新条目
            await setLorebookEntries(currentWorldBook, updatedEntries);

            // 更新完成后刷新条目列表
            await loadEntries(currentWorldBook);

            // 重新加载批量处理视图
            displayBatchEntries();

            alert(`成功更新 ${selectedEntries.size} 个条目`);
          } catch (error) {
            console.error('批量更新失败', error);
            alert('批量更新失败: ' + error.message);
          } finally {
            batchLoading.style.display = 'none';
          }
        }

        // 函数 - 应用批量修改
        async function applyBatchChanges() {
          if (selectedEntries.size === 0) {
            alert('请先选择要修改的条目');
            return;
          }

          // 收集要修改的属性
          const changes = {};

          if (batchType.value) {
            changes.type = batchType.value;
          }

          if (batchPosition.value) {
            changes.position = batchPosition.value;
          }

          if (batchDepth.value !== '') {
            changes.depth = parseInt(batchDepth.value);
          }

          if (batchOrder.value !== '') {
            changes.order = parseInt(batchOrder.value);
          }

          if (batchProbability.value !== '') {
            changes.probability = parseInt(batchProbability.value);
          }

          // 检查是否有要修改的属性
          if (Object.keys(changes).length === 0) {
            alert('请选择至少一个要修改的属性');
            return;
          }

          // 确认修改
          if (!confirm(`确定要修改选中的 ${selectedEntries.size} 个条目吗？`)) {
            return;
          }

          batchLoading.style.display = 'block';

          try {
            const updatedEntries = [];

