          toggleBatchViewBtn.textContent = isBatchViewCompact ? '切换完整视图' : '切换紧凑视图';
          displayBatchEntries(); // 重新渲染列表
        });
      });

      /**
       * 规整世界书文本格式
       * @param {string} text 原始文本
       * @returns {string} 格式化后的文本
       */
      function formatWorldBookText(text) {
        const lines = text.split('\n');
        const formattedLines = [];
        let inContentBlock = false;
        let previousLine = '';

        for (const line of lines) {
          const trimmedLine = line.trim();

          if (
            trimmedLine.startsWith('uid:') ||
            trimmedLine.startsWith('trigger:') ||
            trimmedLine.startsWith('content:')
          ) {
            // 顶层关键字，顶格
            formattedLines.push(trimmedLine);
            inContentBlock = trimmedLine.startsWith('content:') && trimmedLine.endsWith('|');
          } else if (
            previousLine.trim() === 'trigger:' ||
            trimmedLine.match(/^(type|position|Title|Comma_separated_list):/)
          ) {
            // trigger下的关键字或明确的二级关键字，缩进2格
            formattedLines.push('  ' + trimmedLine);
            inContentBlock = false;
          } else if (inContentBlock && trimmedLine) {
            // content块下的非空行，缩进2格
            formattedLines.push('  ' + trimmedLine);
          } else {
            // 保留空行或其他未识别的行（保持原样或顶格）
            // 这里选择保留空行，其他行顶格处理
            formattedLines.push(trimmedLine);
            inContentBlock = false; // 遇到非content内容，退出content块状态
          }

          // 记录上一行（处理后的行），用于判断下一行的缩进
          if (trimmedLine) {
            previousLine = formattedLines[formattedLines.length - 1];
          }
        }

        // 使用换行符重新组合，并在每个 uid: 前（除了第一个）加一个空行增加间距
        let result = '';
        for (let i = 0; i < formattedLines.length; i++) {
          if (i > 0 && formattedLines[i].startsWith('uid:')) {
            result += '\n'; // 在非首个uid前加空行
          }
          result += formattedLines[i] + '\n';
        }

        return result.trimEnd(); // 移除末尾可能的多余换行符
      }

      // 新增：函数 - 对条目数组进行排序
      function sortEntries(entriesToSort, mode) {
        if (mode === 'uid') {
          // 按 UID 升序排序
          return [...entriesToSort].sort((a, b) => a.uid - b.uid);
        } else if (mode === 'position') {
          // 按位置/顺序排序
          const positionOrder = [
            'before_character_definition',
            'after_character_definition',
            'before_example_messages',
            'after_example_messages',
            'before_author_note',
            'after_author_note',
            'at_depth_as_system',
            'at_depth_as_assistant',
            'at_depth_as_user',
          ];

          return [...entriesToSort].sort((a, b) => {
            const posIndexA = positionOrder.indexOf(a.position);
            const posIndexB = positionOrder.indexOf(b.position);

            // 比较位置类别
            if (posIndexA !== posIndexB) {
              return posIndexA - posIndexB;
            }

            // 如果位置类别相同
            const isDepthSortA = a.position.startsWith('at_depth_as_');
            const isDepthSortB = b.position.startsWith('at_depth_as_'); //理论上类别相同时，这个应该和上面一致

            if (isDepthSortA) {
              // @D 条目排序：先按 depth 降序，再按 order 升序
              const depthA = a.depth === null ? -Infinity : a.depth; // 将 null 视为最低深度
              const depthB = b.depth === null ? -Infinity : b.depth;
              if (depthB !== depthA) {
                return depthB - depthA; // 降序
              }
              return a.order - b.order; // depth 相同则按 order 升序
            } else {
              // 非 @D 条目排序：按 order 升序
              return a.order - b.order;
            }
          });
        } else {
          // 未知排序模式，返回原数组
          console.warn('Unknown sort mode:', mode);
          return entriesToSort;
        }
      }
