        // 事件监听器 - 导入条目按钮
        importEntriesBtn.addEventListener('click', function () {
          if (!currentWorldBook) {
            alert('请先选择一个世界书');
            return;
          }

          // 清空之前的导入内容和结果
          // 注意：这里保留原有内容，因为可能已经被外部正则替换
          // 如果需要清空，取消下面这行的注释
          // importContent.value = '';

          importPreview.style.display = 'none';
          previewList.innerHTML = '';
          importResult.style.display = 'none';
          importResultContent.innerHTML = '';

          // 更新当前世界书信息显示
