        });

        // 事件监听器 - 预览导入按钮 (原确认导入按钮)
        previewImportBtn.addEventListener('click', async function () {
          // 检查是否选择了世界书
          if (!currentWorldBook) {
            alert('当前未选择世界书，点击返回后选择世界书，然后点击导入生成的世界书再次导入');
            return;
          }

          // 直接使用文本区域的内容
          const content = importContentTextarea.value.trim();

          if (!content) {
