              // 重置批量处理状态
              selectedEntries.clear();
              selectAllCheckbox.checked = false;
              updateSelectedCounter();

              // 重新加载批量处理视图
              displayBatchEntries();

              alert(`成功删除 ${selectedEntries.size} 个条目`);
