              batchLoading.style.display = 'none';
            }
          }
        });

        // 事件监听器 - 批量启用
        batchEnableBtn.addEventListener('click', function () {
          applyBatchPropertyChange('enabled', true);
        });

        // 事件监听器 - 批量禁用
        batchDisableBtn.addEventListener('click', function () {
          applyBatchPropertyChange('enabled', false);
        });

        // 事件监听器 - 应用批量修改
        applyBatchChangesBtn.addEventListener('click', function () {
          applyBatchChanges();
        });

        // 事件监听器 - 取消批量处理
        cancelBatchBtn.addEventListener('click', function () {
          showView('list');
        });

        // 函数 - 显示批量处理条目
        function displayBatchEntries() {
          batchEntryList.innerHTML = '';
          batchEntryList.className = isBatchViewCompact
            ? 'entry-list batch-entry-list compact'
            : 'entry-list batch-entry-list'; // 应用紧凑类名
          batchLoading.style.display = 'block'; // 开始显示前，显示加载中
          noBatchEntriesMessage.style.display = 'none'; // 隐藏无条目消息

          // 获取搜索条件
          const searchTerm = batchSearchInput.value.toLowerCase();

          // 筛选条目
          let batchFilteredEntries = entries;

          if (searchTerm) {
            batchFilteredEntries = entries.filter(
              entry =>
                entry.comment.toLowerCase().includes(searchTerm) ||
                entry.content.toLowerCase().includes(searchTerm) ||
                entry.keys.some(k => k.toLowerCase().includes(searchTerm)) ||
                entry.uid.toString().includes(searchTerm),
            );
          }

          if (batchFilteredEntries.length === 0) {
            noBatchEntriesMessage.style.display = 'block';
            batchLoading.style.display = 'none'; // 没有条目，也要隐藏加载中
            return;
          }

          noBatchEntriesMessage.style.display = 'none';

          // 显示条目
          batchFilteredEntries.forEach(entry => {
            const entryItem = document.createElement('div');
            entryItem.className = 'entry-item';

            // 添加复选框
            const checkbox = document.createElement('input');
            checkbox.type = 'checkbox';
            checkbox.className = 'entry-checkbox';
            checkbox.dataset.uid = entry.uid;
            checkbox.checked = selectedEntries.has(entry.uid);
            checkbox.addEventListener('change', function () {
              if (checkbox.checked) {
                selectedEntries.add(entry.uid);
              } else {
                selectedEntries.delete(entry.uid);
              }
              updateSelectedCounter();
            });
            entryItem.appendChild(checkbox);

            // 根据条目类型设置不同的边框颜色
            if (entry.type === 'constant') {
              entryItem.style.borderLeftColor = '#3a7bd5'; // 使用主色调变量
            } else if (entry.type === 'selective') {
              entryItem.style.borderLeftColor = '#4caf50'; // 使用成功色变量
            } else if (entry.type === 'vectorized') {
              entryItem.style.borderLeftColor = '#9c27b0'; // 使用一个更明显的紫色
            }

            // 如果条目被禁用，显示灰色
            if (!entry.enabled) {
              entryItem.style.opacity = '0.7';
            }

            const header = document.createElement('div');
            header.className = 'entry-header';

            const title = document.createElement('div');
            title.className = 'entry-title';
            title.textContent = entry.comment || '无标题';

            const statusBadge = document.createElement('span');
            statusBadge.textContent = entry.enabled ? '已启用' : '已禁用';
            statusBadge.style.backgroundColor = entry.enabled ? 'var(--success-color)' : 'var(--danger-color)';
            statusBadge.style.color = 'white';
            statusBadge.style.padding = '0.2rem 0.5rem';
            statusBadge.style.borderRadius = '4px';
            statusBadge.style.fontSize = '0.75rem';

            header.appendChild(title);
            header.appendChild(statusBadge);
            entryItem.appendChild(header);

            const meta = document.createElement('div');
            meta.className = 'entry-meta';

            // 显示UID
            const uidSpan = document.createElement('span');
            uidSpan.textContent = 'UID: ' + entry.uid;
            meta.appendChild(uidSpan);

            // 显示类型
            const typeSpan = document.createElement('span');
            const typeNames = {
              constant: '常量（蓝灯）',
              selective: '选择性（绿灯）',
              vectorized: '向量化（紫灯）',
            };
            typeSpan.textContent = '类型: ' + (typeNames[entry.type] || entry.type);
            meta.appendChild(typeSpan);

            // 显示位置
            const positionSpan = document.createElement('span');
            const positionNames = {
              before_character_definition: '角色定义之前',
              after_character_definition: '角色定义之后',
              before_example_messages: '示例消息之前',
              after_example_messages: '示例消息之后',
              before_author_note: '作者注释之前',
              after_author_note: '作者注释之后',
              at_depth_as_system: '@D⚙',
              at_depth_as_assistant: '@D👤',
              at_depth_as_user: '@D🤖',
            };
            positionSpan.textContent = '位置: ' + (positionNames[entry.position] || entry.position);
            if (entry.position.startsWith('at_depth_as_') && entry.depth !== null) {
              positionSpan.textContent += ` (深度: ${entry.depth})`;
            }
            meta.appendChild(positionSpan);

            // 显示顺序
            const orderSpan = document.createElement('span');
            orderSpan.textContent = '顺序: ' + entry.order;
            meta.appendChild(orderSpan);

            // 显示概率
            const probabilitySpan = document.createElement('span');
            probabilitySpan.textContent = '概率: ' + entry.probability + '%';
            meta.appendChild(probabilitySpan);

            entryItem.appendChild(meta);

            // 显示关键词标签
            if (entry.keys && entry.keys.length > 0) {
              const tagList = document.createElement('div');
              tagList.className = 'tag-list';

              const logicNames = {
                and_any: '任意一个关键词（OR）',
                and_all: '所有关键词（AND）',
                not_all: '排除所有关键词',
                not_any: '排除任意关键词',
              };

              const logicTag = document.createElement('div');
              logicTag.className = 'tag';
              logicTag.style.backgroundColor = '#e1d5e7'; // 浅紫色背景
              logicTag.style.color = '#000';
              logicTag.textContent = logicNames[entry.logic] || entry.logic;
              tagList.appendChild(logicTag);

              entry.keys.forEach(keyword => {
                if (keyword) {
                  const tag = document.createElement('div');
                  tag.className = 'tag';
                  tag.textContent = keyword;
                  tagList.appendChild(tag);
                }
              });

              entryItem.appendChild(tagList);
            }

            // 显示内容预览 (仅在非紧凑模式下)
            if (!isBatchViewCompact) {
              const content = document.createElement('div');
              content.className = 'entry-content';
              content.textContent = entry.content;
              entryItem.appendChild(content);
            }

            batchEntryList.appendChild(entryItem);
          });

          batchLoading.style.display = 'none'; // 条目显示完成，隐藏加载中
        }

        // 函数 - 更新已选择计数
        function updateSelectedCounter() {
          selectedCounter.textContent = `已选择: ${selectedEntries.size} 项`;
        }

        // 函数 - 应用批量属性修改
        async function applyBatchPropertyChange(property, value) {
          if (selectedEntries.size === 0) {
            alert('请先选择要修改的条目');
            return;
          }

          batchLoading.style.display = 'block';

          try {
            const updatedEntries = [];

            // 为每个选中的条目创建更新对象
            for (const uid of selectedEntries) {
              updatedEntries.push({
                uid: uid,
                [property]: value,
              });
            }

            // 更新条目
            await setLorebookEntries(currentWorldBook, updatedEntries);

            // 更新完成后刷新条目列表
            await loadEntries(currentWorldBook);

            // 重新加载批量处理视图
            displayBatchEntries();

            alert(`成功更新 ${selectedEntries.size} 个条目`);
          } catch (error) {
            console.error('批量更新失败', error);
            alert('批量更新失败: ' + error.message);
          } finally {
            batchLoading.style.display = 'none';
          }
        }

        // 函数 - 应用批量修改
        async function applyBatchChanges() {
          if (selectedEntries.size === 0) {
            alert('请先选择要修改的条目');
            return;
          }

          // 收集要修改的属性
          const changes = {};

          if (batchType.value) {
            changes.type = batchType.value;
          }

          if (batchPosition.value) {
            changes.position = batchPosition.value;
          }

          if (batchDepth.value !== '') {
            changes.depth = parseInt(batchDepth.value);
          }

          if (batchOrder.value !== '') {
            changes.order = parseInt(batchOrder.value);
          }

          if (batchProbability.value !== '') {
            changes.probability = parseInt(batchProbability.value);
          }

          // 检查是否有要修改的属性
          if (Object.keys(changes).length === 0) {
            alert('请选择至少一个要修改的属性');
            return;
          }

          // 确认修改
          if (!confirm(`确定要修改选中的 ${selectedEntries.size} 个条目吗？`)) {
            return;
          }

          batchLoading.style.display = 'block';

          try {
            const updatedEntries = [];

            // 为每个选中的条目创建更新对象
            for (const uid of selectedEntries) {
              updatedEntries.push({
                uid: uid,
                ...changes,
              });
            }

            // 更新条目
            await setLorebookEntries(currentWorldBook, updatedEntries);

            // 更新完成后刷新条目列表
            await loadEntries(currentWorldBook);

            // 重新加载批量处理视图
            displayBatchEntries();

            alert(`成功更新 ${selectedEntries.size} 个条目`);
          } catch (error) {
            console.error('批量更新失败', error);
            alert('批量更新失败: ' + error.message);
          } finally {
            batchLoading.style.display = 'none';
          }
        }

        // 函数 - 加载批量处理视图
        function loadBatchView() {
          // 清空选中状态
          selectedEntries.clear();
          selectAllCheckbox.checked = false;
          updateSelectedCounter();

          // 清空搜索框
          batchSearchInput.value = '';

          // 清空批量修改字段
          batchType.value = '';
          batchPosition.value = '';
          batchDepth.value = '';
          batchOrder.value = '';
          batchProbability.value = '';

          // 显示所有条目
          displayBatchEntries();
        }

        // 更新导入视图中的世界书信息
        function updateImportViewWorldBookInfo() {
          const selectedWorldBookName = document.getElementById('selectedWorldBookName');
          const noWorldBookSelected = document.getElementById('noWorldBookSelected');

          if (currentWorldBook) {
            selectedWorldBookName.textContent = `当前选择的世界书: ${currentWorldBook}`;
            selectedWorldBookName.style.display = 'block';
            noWorldBookSelected.style.display = 'none';
          } else {
            selectedWorldBookName.style.display = 'none';
            noWorldBookSelected.style.display = 'block';
          }
        }

        // 新增：世界书搜索框输入事件
        worldBookSearchInput.addEventListener('input', function () {
          displayWorldBooks(worldBookSearchInput.value.trim());
        });

        // 新增：清除世界书搜索按钮点击事件
        clearWorldBookSearchBtn.addEventListener('click', function () {
          worldBookSearchInput.value = '';
          displayWorldBooks('');
        });

        // 新增：在 ST 中启用当前世界书按钮点击事件
        enableWorldBookBtn.addEventListener('click', async function () {
          if (!currentWorldBook) {
            alert('请先选择一个要启用的世界书。');
            return;
          }

          try {
            console.log(`Attempting to enable world book: ${currentWorldBook}`);

            // 1. 获取当前设置
            const settings = await getLorebookSettings();

            // 2. 检查是否已启用
            if (settings.selected_global_lorebooks.includes(currentWorldBook)) {
              alert(`世界书 "${currentWorldBook}" 已经在 SillyTavern 中启用。`);
              return;
            }

            // 3. 添加到启用列表
            const updatedSelectedBooks = [...settings.selected_global_lorebooks, currentWorldBook];
            console.log('Updated selected books:', updatedSelectedBooks);

            // 4. 应用设置
            await setLorebookSettings({ selected_global_lorebooks: updatedSelectedBooks });

            alert(`已在 SillyTavern 中启用世界书 "${currentWorldBook}" 。`);
          } catch (error) {
            console.error('启用世界书失败:', error);
            alert('在 SillyTavern 中启用世界书失败: ' + error.message + '\n请检查控制台获取更多信息。');
          }
        });

        // 新增：格式化导入内容按钮点击事件
        formatImportBtn.addEventListener('click', function () {
          const currentContent = importContentTextarea.value;
          const formattedContent = formatWorldBookText(currentContent);
          importContentTextarea.value = formattedContent;
          // 格式化后自动调整高度
          autoGrowTextarea(importContentTextarea);
        });

        // 新增：排序按钮点击事件
        sortEntriesBtn.addEventListener('click', function () {
          // 切换排序模式
          currentSortMode = currentSortMode === 'uid' ? 'position' : 'uid';
          // 更新按钮文本
          sortEntriesBtn.textContent = `当前排序: ${currentSortMode === 'uid' ? 'UID' : '位置/顺序'}`;
          // 重新筛选和显示条目以应用新排序
          filterAndDisplayEntries();
        });

        // 新增：深度筛选输入框事件
        depthFilterInput.addEventListener('input', function () {
          filterAndDisplayEntries(); // 深度变化时重新筛选
        });

        // 新增：切换紧凑视图按钮事件
        toggleBatchViewBtn.addEventListener('click', function () {
          isBatchViewCompact = !isBatchViewCompact;
          toggleBatchViewBtn.textContent = isBatchViewCompact ? '切换完整视图' : '切换紧凑视图';
          displayBatchEntries(); // 重新渲染列表
        });
      });

      /**
       * 规整世界书文本格式
       * @param {string} text 原始文本
       * @returns {string} 格式化后的文本
       */
      function formatWorldBookText(text) {
        const lines = text.split('\n');
        const formattedLines = [];
        let inContentBlock = false;
        let previousLine = '';

        for (const line of lines) {
          const trimmedLine = line.trim();

          if (
            trimmedLine.startsWith('uid:') ||
            trimmedLine.startsWith('trigger:') ||
            trimmedLine.startsWith('content:')
          ) {
            // 顶层关键字，顶格
            formattedLines.push(trimmedLine);
            inContentBlock = trimmedLine.startsWith('content:') && trimmedLine.endsWith('|');
          } else if (
            previousLine.trim() === 'trigger:' ||
            trimmedLine.match(/^(type|position|Title|Comma_separated_list):/)
          ) {
            // trigger下的关键字或明确的二级关键字，缩进2格
            formattedLines.push('  ' + trimmedLine);
            inContentBlock = false;
          } else if (inContentBlock && trimmedLine) {
            // content块下的非空行，缩进2格
            formattedLines.push('  ' + trimmedLine);
          } else {
            // 保留空行或其他未识别的行（保持原样或顶格）
            // 这里选择保留空行，其他行顶格处理
            formattedLines.push(trimmedLine);
            inContentBlock = false; // 遇到非content内容，退出content块状态
          }

          // 记录上一行（处理后的行），用于判断下一行的缩进
          if (trimmedLine) {
            previousLine = formattedLines[formattedLines.length - 1];
          }
        }

        // 使用换行符重新组合，并在每个 uid: 前（除了第一个）加一个空行增加间距
        let result = '';
        for (let i = 0; i < formattedLines.length; i++) {
          if (i > 0 && formattedLines[i].startsWith('uid:')) {
            result += '\n'; // 在非首个uid前加空行
          }
          result += formattedLines[i] + '\n';
        }

        return result.trimEnd(); // 移除末尾可能的多余换行符
      }

      // 新增：函数 - 对条目数组进行排序
      function sortEntries(entriesToSort, mode) {
        if (mode === 'uid') {
          // 按 UID 升序排序
          return [...entriesToSort].sort((a, b) => a.uid - b.uid);
        } else if (mode === 'position') {
          // 按位置/顺序排序
          const positionOrder = [
            'before_character_definition',
            'after_character_definition',
            'before_example_messages',
            'after_example_messages',
            'before_author_note',
            'after_author_note',
            'at_depth_as_system',
            'at_depth_as_assistant',
            'at_depth_as_user',
          ];

          return [...entriesToSort].sort((a, b) => {
            const posIndexA = positionOrder.indexOf(a.position);
            const posIndexB = positionOrder.indexOf(b.position);

            // 比较位置类别
            if (posIndexA !== posIndexB) {
              return posIndexA - posIndexB;
            }

            // 如果位置类别相同
            const isDepthSortA = a.position.startsWith('at_depth_as_');
            const isDepthSortB = b.position.startsWith('at_depth_as_'); //理论上类别相同时，这个应该和上面一致

            if (isDepthSortA) {
              // @D 条目排序：先按 depth 降序，再按 order 升序
              const depthA = a.depth === null ? -Infinity : a.depth; // 将 null 视为最低深度
              const depthB = b.depth === null ? -Infinity : b.depth;
              if (depthB !== depthA) {
                return depthB - depthA; // 降序
              }
              return a.order - b.order; // depth 相同则按 order 升序
            } else {
              // 非 @D 条目排序：按 order 升序
              return a.order - b.order;
            }
          });
        } else {
          // 未知排序模式，返回原数组
          console.warn('Unknown sort mode:', mode);
          return entriesToSort;
        }
      }
